var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"하하하! 이 몸의 신기술, 플레임 드라이브 맛이 어떠냐!","JPN":"ハハハ！　オレ様の新技、フレイムドライブを食らえ！","ENG":"Hah hah hah! Behold my new skill, the Flame Drive!","TWN":"哈哈哈！我的新技術，驅動火焰如何！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"매 순간마다 성장하는 이 몸의 전투 재능은 그야말로 천재의 경지!","JPN":"止まることなく成長し続けるオレ様の戦闘の才能は、\\nまさに天才の境地！","ENG":"Such a genius! I grow stronger every moment I fight!","TWN":"我的戰鬥能力每瞬間都在成長，簡直就是天才吧！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"엄청 신났네. 실전을 저렇게 즐기는 것도 재능이라니까.","JPN":"すごい楽しそうにしてるな。\\n実戦をあんなに楽しめるのもひとつの才能かも。","ENG":"He seems so happy. Well, enjoying the fight is a sort of talent, I guess.","TWN":"這麼開心，那樣享受實戰也是一種才能呢。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"꺄아아아악!!","JPN":"きゃああああ！！","ENG":"Eeeeek!!","TWN":"啊啊啊啊！！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응……? 비명 소리?","JPN":"うん……？　悲鳴？","ENG":"Huh? A scream?","TWN":"嗯……？尖叫聲？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"저, 저리가! 이 괴물아!","JPN":"ち、近づかないで！　この化け物！","ENG":"G-go away, you monster!","TWN":"走…走開啦！臭怪物！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"누구 목청이 그렇게 큰지 확인하러 왔더니…….","JPN":"こんなデカい叫び声が誰のものか確かめに来たら……","ENG":"So you were the banshee with crazy screams...","TWN":"想說是誰的嗓門那麼大……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"이로하, 왜 대피소가 아니라 여기 있는 거야?","JPN":"いろは、なんで避難所じゃなくてこんなところにいるんだ？","ENG":"Iroha, why are you here? You’re supposed to be in the shelter.","TWN":"伊呂波，你爲什麼不是在避難所，而是在這裡？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"너, 요즘 들어 침식사태가 있을 때마다 이런 식으로 사라졌지?","JPN":"あんたさ、最近侵食事態が起こるたびにこんな風にいなくなってたよね？","ENG":"You’ve been disappearing like this whenever a Corruption disaster occurs.","TWN":"最近每次發生侵蝕事件時，你都是這樣消失的吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"미나토, 너……. 혹시 카운터인 거야?","JPN":"湊、あんた……もしかしてカウンターなの？","ENG":"Minato, are you... a Counter?","TWN":"南裕夏，你…… 是制裁者嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아, 그건…….","JPN":"えっと、それは……","ENG":"Oh, erm...","TWN":"那個……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"후훗, 일반인 주제에 벌써 그 정도 진실까지 다다르다니 제법이군.","JPN":"フッ、一般人のくせにもうその真実にたどり着くとは、なかなかやるな。","ENG":"You are quite smart for an ordinary girl, discerning the truth like that.","TWN":"呵呵，身為一個普通人，竟然這麼快發現真相，有兩下子喔！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"아무래도 더는 숨기지 못할 것 같은데, 미나토.","JPN":"湊、やはりこれ以上は隠せないと思うが。","ENG":"I don’t think you can hide the truth any longer, Minato.","TWN":"我看是藏不住了啦，南裕夏。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"비밀결사 오오가미 흑막조의 나유카 미나토가! 실은 카운터였단 사실을 말이야!","JPN":"秘密結社大神黒幕組の奈由香湊が！\\n実はカウンターだったという事実をな！","ENG":"That you, Nayuka Minato of the Ogami's Shadow Group is actually a Counter!","TWN":"秘密社團 大神黑幕組的南裕夏！其實是制裁者！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그렇게 대단한 거라고 생각하진 않아. 그리 오래된 일도 아니고.","JPN":"そんなたいしたことじゃないよ。\\n自分がカウンターだって気づいたのも割と最近のことだし。","ENG":"There’s nothing special about it. Plus It just happened recently.","TWN":"還好吧？這又不是什麼天大的秘密。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"그럼, 전국대회를 앞두고 동아리를 그만둔 것도 카운터라서야?","JPN":"じゃあ全国大会を前にして部活をやめたのも、カウンターだから？","ENG":"Is it why you left the Archery Club right before the competition?","TWN":"那麼，在全國比賽前退社，也是因為你是制裁者的關係嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"응. 일단은 카운터니까. 일반인으로 나가는 건 공평하지 못하잖아.","JPN":"うん。一応はカウンターだから。\\n一般人として出るのはフェアじゃないだろ。","ENG":"Yes, well, a Counter competing with ordinary people is not fair.","TWN":"嗯，因為我是制裁者，用普通人的身分出賽是不公平的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"미안해, 이로하. 일부러 속이려고 한 건 아니었어.","JPN":"ごめん、いろは。騙そうと思ってたつもりはないんだ。","ENG":"I’m sorry, Iroha. I didn’t mean to lie to you.","TWN":"對不起，伊呂波。我不是故意要騙你的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"딱히…… 실망하진 않았어.","JPN":"別に……ガッカリしてないよ。","ENG":"I’m not... disappointed.","TWN":"其實……我沒有很失望啦。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"그래. 그동안 라이벌로 여겼던 경쟁자가 한 명 사라졌으니 오히려 잘됐지, 뭐.","JPN":"そうだね。今までライバルだと思ってた人が1人減ったんだから、むしろよかった。","ENG":"Yes, rather, I’m glad that one of my rivals is gone.","TWN":"沒錯，少一個競爭對手也好吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하하…….","JPN":"はは……","ENG":"Hah hah...","TWN":"哈哈……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"그런데 카운터란 건 왜 여태 숨겼어? 마사키처럼 비밀단원 놀이라도 하려고?","JPN":"ところでカウンターだってことをなんで今まで隠してたの？\\n雅紀みたいに秘密結社ごっこでもするつもり？","ENG":"But why didn’t you tell me that you were a Counter? Were you playing that secret organization thing like Masaki?","TWN":"不過你為什麼要隱瞞制裁者的身分？你是想像雅紀一樣搞神秘嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그냥, 나 같은 게 갑자기 카운터라고 밝혀도 별로 믿기지 않잖아.","JPN":"いや、僕みたいなのが急にカウンターだと明かしても、\\nあまり信じられないだろ。","ENG":"No particular reason. I didn’t think people would believe me if I told them I was a Counter.","TWN":"因為突然我說是制裁者，應該沒有人會相信吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"괜히 애들 놀라게 하는 것보단, 예전처럼 지내고 싶었어.","JPN":"周りを驚かせてしまうよりも、今までどおり過ごしたかっただけさ。","ENG":"I didn’t want to surprise you. All I wanted was to hang out with y’all like before.","TWN":"與其嚇到同學們，不如像以前一樣就好。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"뭐야, 그게.","JPN":"何よ、それ。","ENG":"What?","TWN":"什麼嘛～"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"이상해. 보통은 자랑하고 싶어서 안달일 텐데.","JPN":"おかしいよ。普通は自慢したくてしょうがないはずなのに。","ENG":"That’s weird. Others would have bragged about it if they became a Counter.","TWN":"奇怪，一般都是想趁機炫耀吧？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"그런가……. 나는 잘 모르겠는데…….","JPN":"そうかな……僕にはわからないな……","ENG":"Really? I don’t know...","TWN":"是嗎…這我不知道……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"하여간…….","JPN":"まったく……","ENG":"Oh, jeez...","TWN":"總之……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"……하던 비밀결사 놀이 마저 해. 난 학교로 가 봐야겠다.","JPN":"……あんたたちはここで秘密結社ごっこを続けて。\\n私は学校に行ってみるから。","ENG":"Okay, have fun playing the secret organization thing. I’m going back to the school.","TWN":"……你們就繼續玩秘密社團遊戲吧。我要去一趟學校。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"잠깐만. 이로하.","JPN":"ちょっと待って、いろは。","ENG":"Wait, Iroha.","TWN":"等一下，伊呂波。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"왜? 비밀이라도 지켜 달라고 하게?","JPN":"なに？　秘密を守ってほしいとでも言いたいの？","ENG":"What? You want me to keep your secret?","TWN":"幹嘛？是要叫我不要告訴別人嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"아니, 너 다리에서 피가 나고 있잖아.","JPN":"いや、足から血が出てるだろ。","ENG":"No, your leg is bleeding.","TWN":"不是，你的腿在流血欸。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"아…….","JPN":"あ……","ENG":"Oh...","TWN":"呃……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"네가 해치워 준 침식체 발톱에 살짝 긁혔나 봐. 이 정도는 약 바르면 금방 나아.","JPN":"あんたが倒した侵食体に少し引っかかれたみたい。\\nこれぐらい薬を塗ればすぐ治るよ。","ENG":"The C.O. you killed must have scratched me. I’ll be fine.","TWN":"好像被你除掉的那隻侵蝕體抓傷的，這點小傷擦個藥很快就沒事的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STUDENT_NPC_ARCHERY_GIRL","text":{"KOREA":"아니……. 그러고 보니까 좀 어지러운 것 같기도 하고…….","JPN":"いや……そういえばちょっとクラクラするような……","ENG":"I’m a bit dizzy though...","TWN":"不過…現在突然覺得有點暈……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STUDENT_NPC_ARCHERY_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"이로하! 정신 차려, 이로하!","JPN":"いろは！　しっかりしろ、いろは！","ENG":"Iroha! Wake up, Iroha!","TWN":"伊呂波！你醒醒，伊呂波！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"의식을 잃은 거야? 어쩌지? 얼른 병원부터 데려가야 하나?","JPN":"意識を失ったのか？　どうする？\\n今すぐ病院に連れて行くべきか？","ENG":"She fainted? What do we do? Shall we take her to the hospital?","TWN":"暈過去啦？ 怎麼辦？要趕緊把她帶到醫院嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"내가 업을게! 좀 도와줘, 마사키!","JPN":"僕が背負うから手を貸して、雅紀！","ENG":"I’ll carry her on my back! Help me, Masaki!","TWN":"我來揹吧！幫我一下，雅紀！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"저건…… 대형 침식체? 아직 저런 게 남아 있었어?","JPN":"あれは……大型侵食体？\\nまだあんなものが残ってたのか！","ENG":"Is that... a giant C.O.? Was there something like that still left?","TWN":"那是…… 大型侵蝕體？竟然還沒被消滅？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"쳇, 하필 이럴 때……!","JPN":"チッ、よりによってこんな時に……！","ENG":"Darn, this is not the best time.","TWN":"嗟，偏偏挑這種時候……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"미나토! 내가 저 녀석 시선을 끌겠다! 그 사이에 여자애를 데려가!","JPN":"湊！　オレが囮になる！　その間にその子を連れていけ！","ENG":"Minato! Take the girl while I distract it!","TWN":"南裕夏！我去引開那傢伙！ 你就趁機帶她走！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"기다려, 마사키! 저런 괴물 상대로……!","JPN":"待て、雅紀！　あんな化け物を相手に……！","ENG":"Wait, Masaki! That one’s too big—","TWN":"等一下，雅紀！ 那種怪物……！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"미나토…… 너 방금 봤냐?","JPN":"湊……今の見たか？","ENG":"Minato... Did you see that?","TWN":"南裕夏…… 你剛有看到嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"……응. 바람이 불더니, 침식체가 두 동강 났어.","JPN":"……ああ。風が吹いて、侵食体が真っ二つになった。","ENG":"... Yes. A wind blew, and it was cut in half.","TWN":"……嗯。突然颳起一陣風，接著侵蝕體就斷成兩截。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"괜찮으신가요, 여러분?","JPN":"大丈夫でしょうか、皆様？","ENG":"Are you alright?","TWN":"還好嗎，各位！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};